<?php require_once __DIR__.'/../includes/bootstrap.php';require_auth();require_role($pdo,['admin']);$users=(int)$pdo->query("SELECT COUNT(*) FROM users")->fetchColumn();$teams=(int)$pdo->query("SELECT COUNT(*) FROM teams")->fetchColumn();$tasks=(int)$pdo->query("SELECT COUNT(*) FROM tasks")->fetchColumn();$logs=$pdo->query("SELECT a.*,u.name FROM activity_logs a JOIN users u ON u.id=a.user_id ORDER BY a.id DESC LIMIT 100")->fetchAll();$pageTitle='Admin Console';$activePage='admin';require __DIR__.'/../includes/header.php';?><section class="hero-row"><div><p class="eyebrow">SYSTEM ADMINISTRATION</p><h2>Platform overview.</h2><p>Monitor users, teams, tasks and activity.</p></div></section><section class="stats-grid"><article class="stat-card"><div><small>Users</small><strong><?=$users?></strong></div></article><article class="stat-card"><div><small>Teams</small><strong><?=$teams?></strong></div></article><article class="stat-card"><div><small>Tasks</small><strong><?=$tasks?></strong></div></article><article class="stat-card"><div><small>Events</small><strong><?=count($logs)?></strong></div></article></section><section class="panel table-wrap"><table><thead><tr><th>User</th><th>Action</th><th>Details</th><th>Date</th></tr></thead><tbody><?php foreach($logs as $l):?><tr><td><?=e($l['name'])?></td><td><?=e($l['action'])?></td><td><?=e($l['details'])?></td><td><?=e($l['created_at'])?></td></tr><?php endforeach;?></tbody></table></section><?php require __DIR__.'/../includes/footer.php';?>